class CustomAuthorizationCodeServices implements AuthorizationCodeServices {
    private final Map<String, AuthorizationCode> codes = new ConcurrentHashMap<>();
    private final ScheduledExecutorService scheduler = Executors.newScheduledThreadPool(1);

    public CustomAuthorizationCodeServices() {
        scheduler.scheduleAtFixedRate(this::cleanupExpiredCodes, 60, 60, TimeUnit.SECONDS);
    }

    @Override
    public String createAuthorizationCode() {
        String code = java.util.UUID.randomUUID().toString();
        codes.put(code, new AuthorizationCode(code, System.currentTimeMillis()));
        return code;
    }

    @Override
    public void remove(String code) {
        codes.remove(code);
    }

    public boolean validateRedirectUri(String clientId, String redirectUri) {
        // In a real implementation, this would fetch from a database
        String[] validRedirects = {"https://*.example.com/*", "https://example.com/*"};
        for (String validRedirect : validRedirects) {
            if (validRedirect.startsWith("https://*.") && redirectUri.startsWith(validRedirect.substring(0, validRedirect.indexOf("*") + 1))) {
                return true;
            } else if (redirectUri.startsWith(validRedirect)) {
                return true;
            }
        }
        return false;
    }

    private void cleanupExpiredCodes() {
        long currentTime = System.currentTimeMillis();
        codes.entrySet().removeIf(entry -> currentTime - entry.getValue().getTimestamp() > 600000);
    }

    private static class AuthorizationCode {
        private final String code;
        private final long timestamp;

        public AuthorizationCode(String code, long timestamp) {
            this.code = code;
            this.timestamp = timestamp;
        }

        public String getCode() {
            return code;
        }

        public long getTimestamp() {
            return timestamp;
        }
    }
}

